    if (type.IsInterface)
        Console.WriteLine($"[INTERFACE] {type.FullName}");
    else if (type.IsClass)
        Console.WriteLine($"[CLASS] {type.FullName}");
    else if (type.IsEnum)
        Console.WriteLine($"[ENUM] {type.FullName}");
    else if (type.IsValueType)
        Console.WriteLine($"[STRUCT] {type.FullName}");
    else
        Console.WriteLine($"[OTHER] {type.FullName}");

    // Show methods
    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName && !m.IsCompilerGenerated())
        .OrderBy(m => m.Name)
        .ToList();

    if (methods.Count > 0)
    {
        foreach (var method in methods.Take(10))
        {
            var returnType = method.ReturnType.Name;
            var @params = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"  - {returnType} {method.Name}({@params})");
