using System.ComponentModel;
using System.Text.RegularExpressions;

/// <summary>
/// Provides web search and page-fetching tools for the research agent.
/// </summary>
public static partial class WebSearchTool
{
    private static readonly HttpClient HttpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
        },
    };

    [Description("Search the web for information. Returns titles and snippets from search results.")]
    public static async Task<string> SearchWeb(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await HttpClient.GetStringAsync(url, cancellationToken);
            var results = ExtractSearchResults(html);
            return results.Length > 0
                ? results
                : "No results found for the query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch and read the text content of a specific web page.")]
    public static async Task<string> FetchPage(
        [Description("The full URL of the page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var html = await HttpClient.GetStringAsync(url, cancellationToken);
            var text = StripHtml(html);
            return text.Length > 4000
                ? string.Concat(text.AsSpan(0, 4000), "\n[Content truncated]")
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string ExtractSearchResults(string html)
    {
        var results = new List<string>();

        // Extract result blocks from DuckDuckGo HTML search results
        var resultBlocks = ResultBlockRegex().Matches(html);

        foreach (Match block in resultBlocks.Take(8))
        {
            var titleMatch = TitleRegex().Match(block.Value);
            var snippetMatch = SnippetRegex().Match(block.Value);
            var urlMatch = UrlRegex().Match(block.Value);

            var title = titleMatch.Success ? StripHtml(titleMatch.Groups[1].Value).Trim() : "";
            var snippet = snippetMatch.Success ? StripHtml(snippetMatch.Groups[1].Value).Trim() : "";
            var link = urlMatch.Success ? urlMatch.Groups[1].Value.Trim() : "";

            if (!string.IsNullOrWhiteSpace(title))
            {
                var entry = $"Title: {title}";
                if (!string.IsNullOrWhiteSpace(link))
                    entry += $"\nURL: {link}";
                if (!string.IsNullOrWhiteSpace(snippet))
                    entry += $"\nSnippet: {snippet}";
                results.Add(entry);
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "";
    }

    private static string StripHtml(string html)
    {
        // Remove script and style blocks
        html = ScriptStyleRegex().Replace(html, "");
        // Decode common HTML entities
        html = html
            .Replace("&nbsp;", " ")
            .Replace("&amp;", "&")
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#39;", "'")
            .Replace("&#x27;", "'");
        // Remove all HTML tags
        html = TagRegex().Replace(html, " ");
        // Normalize whitespace
        html = WhitespaceRegex().Replace(html, " ");
        return html.Trim();
    }

