    private static partial Regex ResultBlockRegex();

    [GeneratedRegex(@"class=""result__a""[^>]*>(.*?)</a>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex TitleRegex();

    [GeneratedRegex(@"class=""result__snippet""[^>]*>(.*?)</(?:a|span)>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex(@"class=""result__url""[^>]*href=""(.*?)""", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex UrlRegex();

    [GeneratedRegex(@"<(script|style)[^>]*>.*?</\1>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStyleRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex TagRegex();

    [GeneratedRegex(@"\s+")]
    private static partial Regex WhitespaceRegex();
}

using System.ComponentModel;
using System.Text;

/// <summary>
/// Provides note-taking tools for the research agent to record and retrieve findings.
/// </summary>
public sealed class ResearchNotes
{
    private readonly List<(string Topic, string Content)> _notes = [];

    [Description("Save a research note. Use this to record key findings as you research.")]
    public string AddNote(
        [Description("A short heading or topic for this note")] string topic,
        [Description("The detailed content of the note")] string content)
    {
        _notes.Add((topic, content));
        return $"Note #{_notes.Count} saved: \"{topic}\"";
    }

    [Description("Retrieve all saved research notes to review before writing the summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"── Note {i + 1}: {_notes[i].Topic} ──");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

