using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

// Build the chat client pipeline with automatic function invocation
IChatClient chatClient = new ChatClientBuilder(
        new OpenAIClient(apiKey)
            .GetChatClient("gpt-4o-mini-2024-07-18")
            .AsChatClient())
    .UseFunctionInvocation()
    .Build();

// Create tool instances
var notes = new ResearchNotes();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.SearchWeb),
    AIFunctionFactory.Create(WebSearchTool.FetchPage),
    AIFunctionFactory.Create(notes.AddNote),
    AIFunctionFactory.Create(notes.GetNotes),
};

// Create the research agent with instructions and tools
var agent = new ChatClientAgent(
    chatClient: chatClient,
    instructions: """
        You are a thorough research agent. When given a topic, follow this process:

        1. Search the web with 2–3 different queries to gather diverse perspectives.
        2. Fetch the most promising pages to read detailed content.
        3. Take structured notes on key findings as you go.
        4. After sufficient research, retrieve your notes and produce a comprehensive summary.

        Guidelines:
        - Use specific, targeted search queries.
        - Save notes with clear topic headings.
        - Always cite sources in your final summary.
        - Be factual and objective.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and taking notes",
    tools: tools);

// Determine the research topic from command-line args or use a default
var topic = args.Length > 0
    ? string.Join(" ", args)
    : "the latest advances in quantum computing";

Console.WriteLine($"🔍 Researching: {topic}");
Console.WriteLine(new string('─', 60));

// Create a session and run the agent with streaming output
var session = await agent.CreateSessionAsync(CancellationToken.None);

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic thoroughly and provide a comprehensive summary with sources: {topic}",
    session,
    new ChatClientAgentRunOptions
    {
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
        },
    },
    CancellationToken.None))
{
    if (update.Text is { } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine("✅ Research complete.");

